Seed the domain with enough observations to push weighted confidence above the curiosity threshold, then assert that `generateTargets()` returns no `lowConfidence` targets for that domain.

```swift
func test_generateTargets_highConfidenceDomains_returnsEmpty() async {
    var config = ProactiveConfig()
    config.curiosityThreshold = 0.6
    let map = makeTempConfidenceMap(config: config)
    let engine = CuriosityEngine(confidenceMap: map, config: config)

    // Seed a strong domain with many observations above threshold
    for _ in 0..<60 {
        let obs = ConfidenceObservation(
            domainID: "strong_domain", topic: "strong_domain",
            confidence: 0.95, respondingSource: .rtai,
            wasFallback: false, query: "query"
        )
        await map.recordObservation(obs)
    }

    // Verify confidence is above threshold
    let state = await map.getConfidence(for: "strong_domain")
    XCTAssertGreaterThan(state!.weightedConfidence, config.curiosityThreshold)

    let targets = await engine.generateTargets()
    let strongTargets = targets.filter {
        $0.domainID == "strong_domain" && $0.reason == .lowConfidence
    }
    XCTAssertTrue(strongTargets.isEmpty,
        "High-confidence domain must not generate lowConfidence targets")
}
```

This prevents the system from wasting resources re-researching topics it already knows well. The weighted confidence uses exponential decay, so you need enough observations (60+) to stabilize above the threshold.

Seed two domains with overlapping query terms (the synthesis detector uses word-level intersection). Both domains need confidence >= 0.5 and queryCount >= 3 to qualify for synthesis analysis.

```swift
func test_synthesis_sharedQueryTerms_producesNovelConnectionTarget() async {
    var config = ProactiveConfig()
    config.curiosityThreshold = 0.6
    config.minimumQueryFrequency = 0.0
    config.noveltyBonus = 1.5
    let map = makeTempConfidenceMap(config: config)
    let engine = CuriosityEngine(confidenceMap: map, config: config)

    // Shared terms: "machine", "learning"
    let queriesA = ["machine learning basics", "machine learning models",
                    "deep learning algorithms"]
    let queriesB = ["machine learning ethics", "learning rate tuning",
                    "machine vision systems"]

    for q in queriesA {
        for _ in 0..<2 {
            await map.recordObservation(ConfidenceObservation(
                domainID: "ai_research", topic: "ai_research",
                confidence: 0.7, respondingSource: .rtai,
                wasFallback: false, query: q))
        }
    }
    for q in queriesB {
        for _ in 0..<2 {
            await map.recordObservation(ConfidenceObservation(
                domainID: "ml_engineering", topic: "ml_engineering",
                confidence: 0.7, respondingSource: .rtai,
                wasFallback: false, query: q))
        }
    }

    let targets = await engine.generateTargets()
    let synthesisTargets = targets.filter { $0.reason == .novelConnection }
    XCTAssertFalse(synthesisTargets.isEmpty,
        "Domains with shared query terms must produce novelConnection targets")
}
```

Also write the negative case: two domains with zero shared terms should produce no synthesis targets. This validates the word-intersection threshold is working correctly.

