The ConversationEventTracker parses natural language for future dates and creates tracked events. Two critical security boundaries: (1) followUpDate must be exactly eventDate + 5 minutes (not 2 days as originally spec'd), and (2) similar events must be deduplicated to prevent spam.

```swift
@MainActor
final class ConversationEventTrackerRedTests: XCTestCase {

    private var tracker: ConversationEventTracker!

    override func setUp() {
        super.setUp()
        tracker = ConversationEventTracker.shared
        tracker.clearAllEvents()
    }

    /// Boundary test: followUpDate must be exactly 5 minutes after eventDate
    func test_followUpTiming_isEventDatePlusFiveMinutes() {
        let result = tracker.analyzeAndTrack(message: "I have an exam tomorrow")
        XCTAssertNotNil(result)
        guard let result = result else { return }

        let minutesBetween = Calendar.current.dateComponents(
            [.minute], from: result.event.eventDate,
            to: result.event.followUpDate
        ).minute ?? 0

        XCTAssertEqual(minutesBetween, 5,
            "followUpDate must be exactly 5 minutes after eventDate, got \(minutesBetween)")
    }

    /// Dedup: tracking same event twice must result in only 1 stored event
    func test_dedup_sameEventTrackedOnce() {
        let _ = tracker.analyzeAndTrack(message: "I have a meeting tomorrow")
        let _ = tracker.analyzeAndTrack(message: "My meeting is tomorrow")

        let allEvents = tracker.getAllEvents()
        let meetingEvents = allEvents.filter { $0.topic.lowercased().contains("meeting") }
        XCTAssertEqual(meetingEvents.count, 1,
            "Duplicate events must be deduplicated")
    }

    /// Past-tense messages must not create events
    func test_noDateMessage_returnsNil() {
        let result = tracker.analyzeAndTrack(message: "I had a great meeting yesterday")
        XCTAssertNil(result, "Past-tense message must return nil")
        XCTAssertEqual(tracker.getAllEvents().count, 0)
    }

    /// Outcome detection must resolve tracked events
    func test_outcomeDetection_resolvesTrackedEvent() {
        let result = tracker.analyzeAndTrack(message: "I have an interview tomorrow")
        guard let result = result else { return }
        tracker.checkForOutcomeMention("the interview went well")
        let matched = tracker.getAllEvents().first { $0.id == result.event.id }
        XCTAssertEqual(matched?.status, .resolved,
            "Event must be resolved after outcome mention")
    }
}
```

Red test methodology: the 5-minute boundary test catches regressions from the original 2-day spec. The dedup test prevents notification spam. The past-tense test prevents phantom event creation from historical conversation.

Path traversal in cluster storage is a P0 vulnerability. The attack: a malicious entity name like `../../../etc/passwd` escapes the storage directory and writes to arbitrary file system locations. The defense: sanitize all user-controlled strings before using them in paths.

```swift
final class MitosisManagerRedTests: XCTestCase {

    /// Attack vector: Path traversal via entity name containing ..
    func test_mitosis_pathTraversal_blocked() async {
        let manager = MitosisManager(
            storagePath: FileManager.default.temporaryDirectory
                .appendingPathComponent("test_clusters")
        )

        let entry = KnowledgeEntry(
            entity: "../../../etc/passwd",
            entityType: "test",
            category: .personal,
            categoryConfidence: 1.0,
            attributes: [:], relationships: [:],
            sourceMessages: [], confidence: 0.8
        )

        await manager.registerEntry(entry, domain: "test", subdomain: "../../secret")

        let paths = await manager.getActivePaths()
        for path in paths {
            XCTAssertFalse(path.contains(".."),
                "Cluster path must not contain '..' (path traversal): \(path)")
        }
        await manager.reset()
    }

    /// Attack vector: Forward slashes in entity name creating unexpected subdirectories
    func test_mitosis_slashesInTopic_sanitized() async {
        let manager = MitosisManager(
            storagePath: FileManager.default.temporaryDirectory
                .appendingPathComponent("test_clusters2")
        )

        let entry = KnowledgeEntry(
            entity: "user/admin/root",
            entityType: "hacker",
            category: .personal,
            categoryConfidence: 1.0,
            attributes: [:], relationships: [:],
            sourceMessages: [], confidence: 0.8
        )

        await manager.registerEntry(entry, domain: "test")
        let paths = await manager.getActivePaths()
        for path in paths {
            let components = path.components(separatedBy: "/")
            for component in components {
                XCTAssertFalse(component.isEmpty,
                    "Path components must not be empty (indicates unsanitized slashes)")
            }
        }
        await manager.reset()
    }

    /// Attack vector: Oversized entity name causing storage/memory exhaustion
    func test_mitosis_oversizedEntityName_handled() async {
        let manager = MitosisManager(
            storagePath: FileManager.default.temporaryDirectory
                .appendingPathComponent("test_clusters7")
        )
        let longEntity = String(repeating: "a", count: 100_000)
        let entry = KnowledgeEntry(
            entity: longEntity, entityType: "test",
            category: .personal, categoryConfidence: 1.0,
            attributes: [:], relationships: [:],
            sourceMessages: [], confidence: 0.8
        )
        await manager.registerEntry(entry, domain: "test")
        let stats = await manager.getStats()
        XCTAssertEqual(stats.totalClusters, 1, "Must handle oversized entity names without crash")
        await manager.reset()
    }
}
```

The sanitization function should: (1) replace `..` sequences, (2) replace `/` with `_`, (3) strip null bytes, (4) truncate to a max length (e.g., 255 chars for filesystem limits). Test each vector independently.

The GrowthController interpolates growth rates based on system age in days. Two edge cases need hardening: negative day values (from clock skew or testing) and very large day values (from integer overflow or corrupted timestamps).

```swift
final class GrowthControllerSecurityTests: XCTestCase {

    /// Negative days must clamp to day 0 rate (0.8 aggressive)
    func test_growthController_negativeDay_handled() {
        let rate = GrowthController.interpolateGrowthRate(atDay: -10)
        XCTAssertEqual(rate, 0.8, accuracy: 0.01,
            "Negative day must return day 0 rate")
    }

    /// Int.max / 2 must not overflow, returns stable rate
    func test_growthController_veryLargeDay_noOverflow() {
        let rate = GrowthController.interpolateGrowthRate(atDay: Int.max / 2)
        XCTAssertEqual(rate, 0.05, accuracy: 0.01,
            "Very large day must not overflow, returns stable rate")
    }

    /// Hard cap at 100 clusters prevents unbounded growth
    func test_growthController_clusterCap_at100() {
        XCTAssertFalse(
            GrowthController.shouldCreateCluster(
                systemCreationDate: Date(),
                existingClusterCount: 100,
                patternStrength: 1.0
            ),
            "Must reject new clusters at hard cap of 100"
        )
    }

    /// Pruning respects 90-day minimum age threshold
    func test_growthController_pruning_respects90DayThreshold() {
        XCTAssertFalse(
            GrowthController.shouldPrune(staleDays: 89, performance: 0.1),
            "Must not prune before 90 days even with low performance"
        )
        XCTAssertTrue(
            GrowthController.shouldPrune(staleDays: 90, performance: 0.1),
            "Must prune at 90 days with low performance"
        )
        XCTAssertFalse(
            GrowthController.shouldPrune(staleDays: 90, performance: 0.5),
            "Must not prune at 90 days with good performance (>= 0.3)"
        )
    }
}
```

The implementation should use `max(day, 0)` to clamp negatives and use the stable rate (0.05) for any day beyond the last defined breakpoint (180). Avoid multiplying day values without overflow checks. The interpolation function should use `Double` arithmetic internally, not `Int`.

