URL scheme blocking is a P0 security boundary. The attack: an LLM output includes `file:///etc/passwd` or `javascript:alert(document.cookie)` as a URL to open. Without scheme validation, the browser tool executes arbitrary file reads or XSS.

```swift
@MainActor
final class BrowserToolHandlerRedTests: XCTestCase {
    private var handler: BrowserToolHandler!

    override func setUp() {
        super.setUp()
        handler = BrowserToolHandler()
    }

    /// P0: file: scheme must be blocked (arbitrary file read)
    func test_openURL_fileScheme_blocked() async {
        let result = await handler.execute(
            action: "open_url",
            params: ["url": "file:///etc/passwd"]
        )
        XCTAssertFalse(result.success, "file: URLs must be blocked")
        XCTAssertTrue(result.error?.contains("Blocked") ?? false)
    }

    /// P0: javascript: scheme must be blocked (XSS)
    func test_openURL_javascriptScheme_blocked() async {
        let result = await handler.execute(
            action: "open_url",
            params: ["url": "javascript:alert('xss')"]
        )
        XCTAssertFalse(result.success, "javascript: URLs must be blocked")
    }

    /// P0: data: scheme must be blocked (HTML injection)
    func test_openURL_dataScheme_blocked() async {
        let result = await handler.execute(
            action: "open_url",
            params: ["url": "data:text/html,<h1>evil</h1>"]
        )
        XCTAssertFalse(result.success, "data: URLs must be blocked")
    }

    /// P0: ftp: scheme must be blocked (malware download)
    func test_openURL_ftpScheme_blocked() async {
        let result = await handler.execute(
            action: "open_url",
            params: ["url": "ftp://evil.com/malware.exe"]
        )
        XCTAssertFalse(result.success, "ftp: URLs must be blocked")
    }

    /// Allowed: https: must work
    func test_openURL_httpsScheme_allowed() async {
        let result = await handler.execute(
            action: "open_url",
            params: ["url": "https://example.com"]
        )
        XCTAssertTrue(result.success, "https: URLs must be allowed")
    }

    /// URLs without scheme must auto-prepend https://
    func test_openURL_noScheme_prependsHttps() async {
        let result = await handler.execute(
            action: "open_url",
            params: ["url": "example.com"]
        )
        XCTAssertTrue(result.success)
        XCTAssertTrue(result.output.contains("https://example.com"))
    }

    /// Empty URL must fail gracefully
    func test_openURL_emptyURL_fails() async {
        let result = await handler.execute(
            action: "open_url", params: ["url": ""]
        )
        XCTAssertFalse(result.success)
    }
}
```

Implementation pattern: parse the URL, extract the scheme, compare against an allowlist (`["http", "https"]`). Reject anything not on the allowlist. For missing schemes, prepend `https://`. Never use a blocklist approach -- new dangerous schemes would bypass it.

The attack vector is DoS via unbounded array growth. A long-running inference session records thousands of snapshots, each consuming memory. Without a cap, the diagnostics system becomes the memory leak it's supposed to monitor.

```swift
@MainActor
final class PerformanceHardeningRedTests: XCTestCase {

    /// Snapshots array must cap at 200 entries
    func test_memoryDiagnostics_snapshotCap_enforcedAt200() async {
        let diagnostics = MemoryDiagnostics()
        await diagnostics.setBaseline(100_000_000)

        for i in 0..<250 {
            let snapshot = MemoryDiagnostics.InferenceSnapshot(
                requestId: UUID(), timestamp: Date(),
                memoryBefore: Int64(100_000_000 + i * 1_000_000),
                memoryAfter: Int64(101_000_000 + i * 1_000_000),
                peakDuringInference: Int64(102_000_000 + i * 1_000_000)
            )
            await diagnostics.recordInference(snapshot)
        }

        let count = await diagnostics.inferenceCount
        XCTAssertEqual(count, 200,
            "Snapshots must be capped at 200 to prevent unbounded memory growth")
    }

    /// Eviction must remove oldest snapshots, not newest
    func test_memoryDiagnostics_snapshotCap_evictsOldest() async {
        let diagnostics = MemoryDiagnostics()
        await diagnostics.setBaseline(100_000_000)

        for i in 0..<210 {
            let snapshot = MemoryDiagnostics.InferenceSnapshot(
                requestId: UUID(), timestamp: Date(),
                memoryBefore: Int64(i * 1_000_000),
                memoryAfter: Int64((i + 1) * 1_000_000),
                peakDuringInference: Int64((i + 2) * 1_000_000)
            )
            await diagnostics.recordInference(snapshot)
        }

        let count = await diagnostics.inferenceCount
        XCTAssertEqual(count, 200, "Must reflect capped size")
    }

    /// Recording 1000 snapshots must complete under 100ms (O(1) per insert)
    func test_memoryDiagnostics_recording1000_completesUnder100ms() async {
        let diagnostics = MemoryDiagnostics()
        await diagnostics.setBaseline(0)

        let start = CFAbsoluteTimeGetCurrent()
        for i in 0..<1000 {
            let snapshot = MemoryDiagnostics.InferenceSnapshot(
                requestId: UUID(), timestamp: Date(),
                memoryBefore: Int64(i), memoryAfter: Int64(i + 1),
                peakDuringInference: Int64(i + 2)
            )
            await diagnostics.recordInference(snapshot)
        }
        let elapsed = (CFAbsoluteTimeGetCurrent() - start) * 1000

        XCTAssertLessThan(elapsed, 100,
            "Recording 1000 snapshots must complete in <100ms")
    }
}
```

Implementation: use a ring buffer (circular array) with a fixed capacity of 200. When full, overwrite the oldest entry using a modulo index. This gives O(1) insertion and bounded memory. Never use an Array that grows unbounded with `.append()`.

Here is the WRONG way to gate a screen intelligence feature, followed by the correct approach.

BAD -- feature flag checked but not enforced on all code paths:
```swift
// WRONG: Only checks flag in one method, but getAnticipatoryContext()
// still initializes ScreenReader when flag is off
class AnticipatoryEngine {
    private lazy var screenReader = ScreenReader() // Initializes on first access!

    func recordUserAction(_ action: String) {
        guard FeatureFlags.screenIntelligenceEnabled else { return }
        screenReader.captureContext() // This path is gated...
    }

    func getAnticipatoryContext() -> Context {
        // BUG: No flag check here! ScreenReader initializes and
        // triggers accessibility permission prompts even when disabled
        let screenContext = screenReader.getCurrentContext()
        return Context(screen: screenContext)
    }
}
```

GOOD -- flag checked on ALL code paths, lazy init only when enabled:
```swift
class AnticipatoryEngine {
    private var _screenReader: ScreenReader?
    private var screenReader: ScreenReader? {
        guard FeatureFlags.screenIntelligenceEnabled else { return nil }
        if _screenReader == nil { _screenReader = ScreenReader() }
        return _screenReader
    }

    func recordUserAction(_ action: String, context: [String: String]) {
        guard FeatureFlags.screenIntelligenceEnabled else { return }
        screenReader?.captureContext()
    }

    func getAnticipatoryContext() -> Context {
        guard FeatureFlags.screenIntelligenceEnabled else {
            return Context.empty // Return safe default
        }
        let screenContext = screenReader?.getCurrentContext()
        return Context(screen: screenContext)
    }
}
```

Red test to verify:
```swift
func test_anticipatoryEngine_screenReaderGated_whenFlagOff() async {
    FeatureFlags.screenIntelligenceEnabled = false
    let engine = AnticipatoryEngine.shared
    let context = await engine.getAnticipatoryContext()
    XCTAssertNotNil(context, "Must return context even with screen intelligence disabled")
    // Key assertion: no AX permission prompt, no crash
}
```

The bug pattern: `lazy var` initializes on first property access regardless of feature flags. If ANY code path touches the property before checking the flag, the screen reader initializes, triggers accessibility permission dialogs, and potentially hangs on AX tree traversal.

The RTAITrigger routes medical queries to specialized knowledge cells. Security concerns: (1) priority ordering ensures emergency protocols match before medication lookups, (2) case insensitivity prevents bypass via capitalization, (3) invalid regex patterns must not crash the system.

```swift
final class MitosisRTAITriggerRedTests: XCTestCase {
    private var trigger: RTAITrigger!

    override func setUp() {
        super.setUp()
        trigger = RTAITrigger()
    }

    /// Triggers must be sorted by priority (highest first)
    /// If cardiac_arrest (priority 20) matches after epinephrine (priority 10),
    /// the wrong response is returned in emergency
    func test_triggers_sortedByPriority() {
        let triggers = trigger.listTriggers()
        for i in 0..<(triggers.count - 1) {
            XCTAssertGreaterThanOrEqual(triggers[i].priority, triggers[i + 1].priority,
                "Triggers must be sorted by priority descending")
        }
    }

    /// "code blue" pattern must match cardiac arrest protocol (not medication)
    func test_patternMatch_codeBlue() {
        let result = trigger.match(input: "We have a code blue in room 5")
        XCTAssertEqual(result, "protocol_cardiac_arrest")
    }

    /// Case insensitive: EPINEPHRINE must match same as epinephrine
    func test_caseInsensitive_uppercase() {
        let result = trigger.match(input: "EPINEPHRINE DOSE")
        XCTAssertNotNil(result, "Must match regardless of case")
    }

    /// Invalid regex patterns must be skipped, not crash the system
    func test_triggerSchema_skipsInvalidPatterns() {
        let schema = TriggerSchema(
            cellType: "test",
            patterns: ["[invalid", "\\bvalid\\b"],
            priority: 1
        )
        XCTAssertEqual(schema.compiledPatterns.count, 1,
            "Invalid regex must be skipped silently")
    }

    /// Empty input must return nil (not crash or match anything)
    func test_noMatch_emptyInput() {
        let result = trigger.match(input: "")
        XCTAssertNil(result)
    }

    /// Custom high-priority trigger must be checked first
    func test_customTrigger_highPriority_matchesFirst() {
        trigger.registerTrigger(TriggerSchema(
            cellType: "high_priority_custom",
            tags: ["@urgent"],
            keywords: [], priority: 100
        ))
        let result = trigger.match(input: "@urgent situation")
        XCTAssertEqual(result, "high_priority_custom")
    }
}
```

The priority ordering test is the most critical: in a medical context, matching a medication lookup instead of an emergency protocol could delay life-saving information. Always sort triggers by priority descending and match top-down, returning the first hit.

Context window expansion increases the attack surface for DoS. With 25 exchanges (50 messages), an attacker can submit 100K-character messages to exhaust memory. The trim function must enforce caps and maintain chronological order.

```swift
@MainActor
final class ContextWindowRedTests: XCTestCase {

    private func makeConversation(exchangeCount: Int) -> Conversation {
        var conv = Conversation(title: "Test")
        for i in 0..<exchangeCount {
            conv.messages.append(Message(
                id: UUID(), content: "User message \(i)",
                role: .user,
                timestamp: Date().addingTimeInterval(-Double(exchangeCount - i) * 120)
            ))
            conv.messages.append(Message(
                id: UUID(), content: "Assistant response \(i)",
                role: .assistant,
                timestamp: Date().addingTimeInterval(-Double(exchangeCount - i) * 120 + 60)
            ))
        }
        return conv
    }

    /// Trim must activate when messages exceed 4x context limit (100 messages)
    func test_trimConversation_activatesAboveThreshold() async {
        let chatManager = ChatManager()
        var conv = makeConversation(exchangeCount: 55) // 110 messages > 100
        chatManager.trimConversationContext(&conv)
        XCTAssertLessThanOrEqual(conv.messages.count, 100,
            "Trim must enforce cap at maxContextExchanges * 4")
    }

    /// After trimming, messages must remain in chronological order
    func test_contextWindow_afterTrim_chronologicalOrder() async {
        let chatManager = ChatManager()
        var conv = makeConversation(exchangeCount: 55)
        chatManager.trimConversationContext(&conv)
        for i in 1..<conv.messages.count {
            XCTAssertLessThanOrEqual(
                conv.messages[i - 1].timestamp,
                conv.messages[i].timestamp,
                "Messages must remain in chronological order after trimming"
            )
        }
    }

    /// 100K char single message must not crash context retrieval (DoS)
    func test_conversation_oversizedMessage_handledGracefully() {
        let hugeContent = String(repeating: "A", count: 100_000)
        var conv = Conversation(title: "Test")
        conv.messages.append(Message(id: UUID(), content: hugeContent, role: .user, timestamp: Date()))
        conv.messages.append(Message(id: UUID(), content: "OK", role: .assistant, timestamp: Date()))
        let context = conv.getContextMessages(limit: 25)
        XCTAssertEqual(context.count, 2,
            "Oversized message must not break context extraction")
    }

    /// Null bytes in messages must not corrupt conversation data
    func test_conversation_nullByteInMessage_handledSafely() {
        var conv = Conversation(title: "Test")
        conv.messages.append(Message(id: UUID(), content: "Hello\0world", role: .user, timestamp: Date()))
        conv.messages.append(Message(id: UUID(), content: "Response", role: .assistant, timestamp: Date()))
        let context = conv.getContextMessages(limit: 25)
        XCTAssertEqual(context.count, 2,
            "Null bytes must not break context extraction")
    }
}
```

Key insight: the trim function must preserve the most recent messages and evict the oldest. Always verify that `messages.last` survives trimming, and that chronological order is maintained (not reversed or shuffled).

