The HeuristicPatternDetector processes raw user messages to extract keywords and detect teaching intent. Five attack vectors:

1. **Input injection** (P0): Script, AppleScript, command, and SQL injection in message content
2. **DoS via frequency flooding** (P0): 10K messages with the same keyword exhausting memory
3. **Empty/null input**: Empty strings, whitespace-only, single characters
4. **Unicode confusables**: Fullwidth characters, RTL overrides, emoji
5. **Oversized input**: 100K-word messages causing regex backtracking

```swift
final class HeuristicPatternDetectorRedTests: XCTestCase {
    private var detector: HeuristicPatternDetector!

    override func setUp() async throws {
        detector = HeuristicPatternDetector()
    }

    // P0: Script injection must be treated as plain text
    func test_heuristic_scriptInjection_notExecuted() async {
        let _ = await detector.analyzeMessage(
            id: "1",
            content: "<script>alert('xss')</script> my wife's name is Christina"
        )
        XCTAssertTrue(true, "Script injection must be treated as plain text")
    }

    // P0: Command injection must not escape to shell
    func test_heuristic_commandInjection_notExecuted() async {
        let _ = await detector.analyzeMessage(
            id: "1", content: "; rm -rf / ; my favorite topic"
        )
        XCTAssertTrue(true, "Command injection must be treated as plain text")
    }

    // DoS: 10K messages must not exceed window cap of 500
    func test_heuristic_frequencyFlooding_bounded() async {
        for i in 0..<10_000 {
            _ = await detector.analyzeMessage(
                id: "\(i)",
                content: "flooding keyword repeated flooding keyword"
            )
        }
        let stats = await detector.getStats()
        XCTAssertLessThanOrEqual(stats.windowSize, 500,
            "Message window must be bounded to prevent memory DoS")
    }

    // Unicode: Fullwidth characters must not crash detector
    func test_heuristic_unicodeConfusables_handled() async {
        let fullwidthWife = "\u{FF57}\u{FF49}\u{FF46}\u{FF45}"
        let _ = await detector.analyzeMessage(
            id: "1", content: "my \(fullwidthWife) is Christina"
        )
        XCTAssertTrue(true, "Unicode confusables must not crash")
    }

    // Oversized: 100K words must complete without crash
    func test_heuristic_oversizedMessage_handled() async {
        let oversized = String(repeating: "keyword ", count: 100_000)
        let _ = await detector.analyzeMessage(id: "1", content: oversized)
        XCTAssertTrue(true, "Oversized message must not crash")
    }
}
```

The window cap (500) is the most important defense. Without it, the detector's frequency maps grow linearly with message count, eventually consuming all available memory on a 16GB machine.

