The RateLimiter controls access to expensive features (knowledge expansion, image generation, thinking model). Key attack vectors: zero limit bypass, cross-feature leakage, and negative quota underflow.

```swift
final class RateLimiterRedTests: XCTestCase {
    private var sut: RateLimiter!

    override func setUp() {
        super.setUp()
        sut = RateLimiter()
        sut.resetAllUsage()
    }

    /// Zero limit must deny immediately (not allow 1 call)
    func test_checkLimit_zeroLimitDeniesImmediately() async throws {
        let denied = try await sut.checkLimit(
            feature: .imageGeneration, limit: 0, period: .daily
        )
        XCTAssertFalse(denied, "A limit of 0 must deny immediately")
    }

    /// Features must be independent (using one doesn't affect another)
    func test_checkLimit_differentFeaturesIndependent() async throws {
        _ = try await sut.checkLimit(feature: .imageGeneration, limit: 1, period: .daily)
        let allowed = try await sut.checkLimit(
            feature: .knowledgeExpansion, limit: 1, period: .daily
        )
        XCTAssertTrue(allowed, "Different features must have independent limits")
    }

    /// Remaining quota must never go negative
    func test_getRemainingQuota_neverNegative() async throws {
        for _ in 0..<5 {
            _ = try await sut.checkLimit(
                feature: .imageGeneration, limit: 3, period: .daily
            )
        }
        let remaining = await sut.getRemainingQuota(
            feature: .imageGeneration, limit: 3, period: .daily
        )
        XCTAssertGreaterThanOrEqual(remaining!, 0,
            "Remaining quota must never be negative")
    }

    /// Exceeding limit must deny on the Nth+1 call
    func test_checkLimit_exceedsLimit() async throws {
        for _ in 0..<3 {
            _ = try await sut.checkLimit(
                feature: .imageGeneration, limit: 3, period: .daily
            )
        }
        let denied = try await sut.checkLimit(
            feature: .imageGeneration, limit: 3, period: .daily
        )
        XCTAssertFalse(denied, "4th call must exceed limit of 3")
    }

    /// nil limit means unlimited access
    func test_checkLimit_nilLimitMeansUnlimited() async throws {
        let allowed = try await sut.checkLimit(
            feature: .knowledgeExpansion, limit: nil, period: .daily
        )
        XCTAssertTrue(allowed, "Nil limit must mean unlimited access")
    }

    /// Different time periods must be independent
    func test_checkLimit_differentPeriodsIndependent() async throws {
        _ = try await sut.checkLimit(feature: .imageGeneration, limit: 1, period: .hourly)
        let hourlyDenied = try await sut.checkLimit(
            feature: .imageGeneration, limit: 1, period: .hourly
        )
        XCTAssertFalse(hourlyDenied)
        let dailyAllowed = try await sut.checkLimit(
            feature: .imageGeneration, limit: 1, period: .daily
        )
        XCTAssertTrue(dailyAllowed, "Different periods must be independent")
    }

    /// Reset clears specific feature/period
    func test_resetUsage_clearsSpecificFeature() async throws {
        _ = try await sut.checkLimit(feature: .imageGeneration, limit: 1, period: .daily)
        sut.resetUsage(feature: .imageGeneration, period: .daily)
        let allowed = try await sut.checkLimit(
            feature: .imageGeneration, limit: 1, period: .daily
        )
        XCTAssertTrue(allowed, "After reset, usage must be allowed again")
    }
}
```

The zero-limit test catches off-by-one errors where `count < limit` allows one call when limit is 0. The negative quota test catches underflow bugs in the remaining calculation. Both are common in rate limiter implementations.

The ProactiveScheduler creates timed notifications based on natural language patterns. Three security boundaries: (1) trigger dates must be accurate, (2) parseAndSchedule must reject text with no date pattern, (3) the callback must fire for items whose trigger date has passed.

```swift
@MainActor
final class ProactiveSchedulerRedTests: XCTestCase {
    private var scheduler: ProactiveScheduler!

    override func setUp() {
        super.setUp()
        scheduler = ProactiveScheduler.shared
        scheduler.resetForTesting()
    }

    /// scheduleFollowUp trigger date must be accurate to within 60 seconds
    func test_scheduleFollowUp_createsItemWithCorrectDate() {
        scheduler.scheduleFollowUp(topic: "quarterly review", inDays: 3)

        let items = scheduler.getScheduledItems()
        XCTAssertEqual(items.count, 1)
        XCTAssertEqual(items[0].type, .conversationFollowUp)

        let expected = Calendar.current.date(byAdding: .day, value: 3, to: Date())!
        let difference = abs(items[0].triggerDate.timeIntervalSince(expected))
        XCTAssertLessThan(difference, 60,
            "Trigger date must be ~3 days from now (within 60s)")
    }

    /// parseAndSchedule must reject text with no date pattern
    func test_parseAndSchedule_noDate_returnsFalse() {
        let result = scheduler.parseAndSchedule("I like pizza")
        XCTAssertFalse(result)
        XCTAssertEqual(scheduler.getScheduledItems().count, 0)
    }

    /// parseAndSchedule must recognize "in N days" pattern
    func test_parseAndSchedule_inNDays_createsItem() {
        let result = scheduler.parseAndSchedule("Emma's birthday is in 3 days")
        XCTAssertTrue(result)

        let items = scheduler.getScheduledItems()
        XCTAssertEqual(items.count, 1)

        let expected = Calendar.current.date(byAdding: .day, value: 3, to: Date())!
        let difference = abs(items[0].eventDate!.timeIntervalSince(expected))
        XCTAssertLessThan(difference, 60)
    }

    /// parseAndSchedule must recognize "tomorrow" pattern
    func test_parseAndSchedule_tomorrow_createsItem() {
        let result = scheduler.parseAndSchedule("My dentist appointment is tomorrow")
        XCTAssertTrue(result)
        let items = scheduler.getScheduledItems()
        XCTAssertEqual(items.count, 1)
    }

    /// 0-day follow-up must have triggerDate <= now (fires immediately)
    func test_onProactiveMessage_callbackWiring() {
        var callbackSet = false
        scheduler.onProactiveMessage = { _ in callbackSet = true }

        scheduler.scheduleFollowUp(
            topic: "deployment check", inDays: 0,
            context: "Did the deployment succeed?"
        )

        let items = scheduler.getScheduledItems()
        XCTAssertEqual(items.count, 1)
        XCTAssertLessThanOrEqual(items[0].triggerDate, Date(),
            "0-day follow-up trigger date must be <= now")
        XCTAssertNotNil(scheduler.onProactiveMessage)
    }

    /// No dedup at schedule time (dedup happens at send time)
    func test_schedulingTwice_createsTwoItems() {
        scheduler.scheduleFollowUp(topic: "alpha", inDays: 2)
        scheduler.scheduleFollowUp(topic: "alpha", inDays: 2)
        XCTAssertEqual(scheduler.getScheduledItems().count, 2,
            "Scheduling same topic twice must create 2 items")
    }
}
```

Critical gotcha: `ProactiveScheduler.start()` crashes in xctest because `UNUserNotificationCenter` requires a valid bundle proxy. Never call `start()` in tests. Instead, test the scheduling logic and callback wiring independently. The 0-day follow-up test validates that items would fire on the first check cycle without actually starting the scheduler.

The original code used `Task.sleep(nanoseconds: 5_000_000)` (5ms) between each token during streaming. For 200 tokens, that's 1000ms of forced waiting. Replacing with `Task.yield()` gives the same cooperative multitasking benefit with near-zero overhead.

```swift
/// Task.yield() for 200 tokens must complete in <50ms
/// (Task.sleep(5ms) would take 1000ms minimum)
func test_taskYield_200tokens_completesUnder50ms() async {
    let start = CFAbsoluteTimeGetCurrent()
    for _ in 0..<200 {
        await Task.yield()
    }
    let elapsed = (CFAbsoluteTimeGetCurrent() - start) * 1000

    XCTAssertLessThan(elapsed, 50,
        "200 Task.yield() calls must complete in <50ms (took \(String(format: "%.1f", elapsed))ms)")
}

/// Direct comparison: yield must be at least 10x faster than sleep
func test_taskYield_vs_sleep_speedup() async {
    // Measure yield
    let yieldStart = CFAbsoluteTimeGetCurrent()
    for _ in 0..<50 { await Task.yield() }
    let yieldTime = CFAbsoluteTimeGetCurrent() - yieldStart

    // Measure sleep
    let sleepStart = CFAbsoluteTimeGetCurrent()
    for _ in 0..<50 {
        try? await Task.sleep(nanoseconds: 5_000_000)
    }
    let sleepTime = CFAbsoluteTimeGetCurrent() - sleepStart

    let speedup = sleepTime / max(yieldTime, 0.000001)
    XCTAssertGreaterThan(speedup, 10,
        "Task.yield must be at least 10x faster than Task.sleep(5ms). Speedup: \(String(format: "%.0f", speedup))x")
}
```

This is a Category 9 (DoS) fix: the forced sleep in the streaming loop was the root cause of UI beachballing on macOS. The sleep blocked the main thread's cooperative scheduling, causing the UI to freeze for the duration of inference. `Task.yield()` gives up the current time slice without a minimum wait, allowing UI updates to process between tokens.

Without deduplication, an LLM that stutters and emits the same tool call twice causes double execution. This is the most common real-world bug in LLM agent systems.

BAD -- no deduplication:
```swift
func parseToolCalls(from response: String) -> [ToolCall] {
    var calls: [ToolCall] = []
    let pattern = "<tool_call>(.*?)</tool_call>"
    let regex = try! NSRegularExpression(pattern: pattern, options: .dotMatchesLineSeparators)
    let matches = regex.matches(in: response, range: NSRange(response.startIndex..., in: response))

    for match in matches {
        if let range = Range(match.range(at: 1), in: response) {
            let json = String(response[range])
            if let call = parseJSON(json) {
                calls.append(call) // BUG: No dedup check!
            }
        }
    }
    return calls
}
```

Real-world impact: LLM outputs:
```
<tool_call>{"name": "create_calendar_event", "arguments": {"title": "Standup", "date": "tomorrow"}}</tool_call>
<tool_call>{"name": "create_calendar_event", "arguments": {"title": "Standup", "date": "tomorrow"}}</tool_call>
```
Result: two identical calendar events created.

FIX -- deduplicate by content hash:
```swift
func parseToolCalls(from response: String) -> [ToolCall] {
    var calls: [ToolCall] = []
    var seen = Set<String>() // Track unique call signatures
    let pattern = "<tool_call>(.*?)</tool_call>"
    let regex = try! NSRegularExpression(pattern: pattern, options: .dotMatchesLineSeparators)
    let matches = regex.matches(in: response, range: NSRange(response.startIndex..., in: response))

    for match in matches {
        if let range = Range(match.range(at: 1), in: response) {
            let json = String(response[range])
            // Dedup by raw JSON string
            let trimmed = json.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !seen.contains(trimmed) else { continue }
            seen.insert(trimmed)

            if let call = parseJSON(json) {
                guard !call.tool.trimmingCharacters(in: .whitespaces).isEmpty else { continue }
                calls.append(call)
            }
        }
    }

    // Cap at 10 to prevent DoS
    return Array(calls.prefix(10))
}
```

Red test:
```swift
func test_parser_duplicateToolCalls_deduplicated() {
    let response = """
    <tool_call>{"name": "create_calendar_event", "arguments": {"title": "Standup"}}</tool_call>
    <tool_call>{"name": "create_calendar_event", "arguments": {"title": "Standup"}}</tool_call>
    """
    let calls = parser.parseToolCalls(from: response)
    XCTAssertEqual(calls.count, 1, "Duplicate tool calls must be deduplicated")
}
```

Three fixes in one: (1) dedup by content hash, (2) reject empty tool names, (3) cap at 10 calls per response. Always apply all three together.

