Key insight: with a 0.95 decay factor, the maximum single-observation delta is `0.05 * |observation - current|`, which caps at approximately 0.04. This means the "critical drop" threshold of 0.15 is unreachable via single observations. Notifications are triggered by trend changes (stable -> improving, stable -> declining), not by single-observation deltas.

```swift
final class MockConfidenceObserver: ConfidenceObserver, @unchecked Sendable {
    private actor State {
        var updateCount: Int = 0
        var criticalDropCount: Int = 0

        func recordUpdate(domain: String, confidence: Double) {
            updateCount += 1
        }
        func recordCriticalDrop() { criticalDropCount += 1 }
        func getUpdateCount() -> Int { updateCount }
        func getCriticalDropCount() -> Int { criticalDropCount }
    }

    private let state = State()

    func confidenceDidUpdate(domain: String, newConfidence: Double, trend: ConfidenceTrend) async {
        await state.recordUpdate(domain: domain, confidence: newConfidence)
    }
    func criticalConfidenceDrop(domain: String, from: Double, to: Double) async {
        await state.recordCriticalDrop()
    }
    func getUpdateCount() async -> Int { await state.getUpdateCount() }
    func getCriticalDropCount() async -> Int { await state.getCriticalDropCount() }
}

/// Observer fires on trend change (stable -> improving)
func test_observer_significantChange_firesCallback() async {
    let map = makeTempConfidenceMap()
    let observer = MockConfidenceObserver()
    await map.addObserver(observer)

    // 5 low observations, then 5 high -> trend changes to .improving
    for _ in 0..<5 {
        await map.recordObservation(makeObservation(
            domainID: "observed", confidence: 0.3))
    }
    for _ in 0..<5 {
        await map.recordObservation(makeObservation(
            domainID: "observed", confidence: 0.9))
    }

    try? await Task.sleep(nanoseconds: 100_000_000)
    let count = await observer.getUpdateCount()
    XCTAssertGreaterThan(count, 0,
        "Observer must fire when trend changes stable -> improving")
}

/// Critical drop (0.15) is unreachable with 0.95 decay
func test_observer_criticalDrop_unreachableWithDefaultConfig() async {
    let map = makeTempConfidenceMap()
    let observer = MockConfidenceObserver()

    for _ in 0..<5 {
        await map.recordObservation(makeObservation(
            domainID: "dropping", confidence: 0.9))
    }
    await map.addObserver(observer)
    for _ in 0..<5 {
        await map.recordObservation(makeObservation(
            domainID: "dropping", confidence: 0.1))
    }

    try? await Task.sleep(nanoseconds: 100_000_000)
    let criticalCount = await observer.getCriticalDropCount()
    XCTAssertEqual(criticalCount, 0,
        "Critical drop (>0.15 single-obs delta) is unreachable with 0.95 decay")
}
```

The MockConfidenceObserver uses an internal actor for thread safety in Swift 6 concurrency mode. Never use `NSLock` from async contexts -- it's unavailable and will cause compiler errors.

The trend is calculated by comparing the average of the recent 5 observations against the older 5 observations. You need at least 10 observations to establish a trend.

```swift
/// Increasing confidence over 10 observations -> .improving
func test_trend_increasingConfidence_improving() async {
    let map = makeTempConfidenceMap()
    // First 5 low, next 5 high
    for conf in [0.3, 0.3, 0.3, 0.3, 0.3, 0.7, 0.7, 0.7, 0.7, 0.7] {
        await map.recordObservation(makeObservation(
            domainID: "trending_up", confidence: conf))
    }
    let state = await map.getConfidence(for: "trending_up")
    XCTAssertEqual(state?.trend, .improving,
        "0.3 -> 0.7 over 10 observations must produce .improving trend")
}

/// Decreasing confidence over 10 observations -> .declining
func test_trend_decreasingConfidence_declining() async {
    let map = makeTempConfidenceMap()
    for conf in [0.8, 0.8, 0.8, 0.8, 0.8, 0.3, 0.3, 0.3, 0.3, 0.3] {
        await map.recordObservation(makeObservation(
            domainID: "trending_down", confidence: conf))
    }
    let state = await map.getConfidence(for: "trending_down")
    XCTAssertEqual(state?.trend, .declining,
        "0.8 -> 0.3 over 10 observations must produce .declining trend")
}
```

Common mistake: using fewer than 10 observations and expecting a non-stable trend. The trend calculation requires a minimum window of 10 to split into two halves for comparison. With fewer observations, the trend stays `.stable`.

