The critical gotcha: any test class that calls VAToolHandler.execute() must disable `FeatureFlags.biometricAuthEnabled` in setUp/tearDown. The VAToolHandler has a biometric auth gate that checks `BiometricAuthManager.shared.isSessionValid` before executing any tool. In xctest, there's no biometric hardware, so the auth gate blocks all execution.

```swift
@MainActor
final class BiometricAuthRedTests: XCTestCase {
    private let manager = BiometricAuthManager.shared

    override func setUp() {
        super.setUp()
        manager.resetForTesting()
    }

    override func tearDown() {
        manager.resetForTesting()
        super.tearDown()
    }

    /// Feature flag OFF -> authenticate() always returns true
    func test_featureFlagDisabled_bypassesAuth() async {
        let original = FeatureFlags.biometricAuthEnabled
        FeatureFlags.biometricAuthEnabled = false

        let result = await manager.authenticate()
        XCTAssertTrue(result, "Auth must succeed when flag is off")
        XCTAssertTrue(manager.isAuthenticated)

        FeatureFlags.biometricAuthEnabled = original
    }

    /// Session timeout: 15 minutes
    func test_sessionExpires_after15Minutes() {
        manager.isAuthenticated = true
        manager.setLastAuthTimeForTesting(
            Date().addingTimeInterval(-901) // 15 min + 1 sec
        )
        XCTAssertFalse(manager.isSessionValid,
            "Session must expire after 15 minutes")
    }

    /// Session within timeout is valid
    func test_sessionValid_within15Minutes() {
        manager.isAuthenticated = true
        manager.setLastAuthTimeForTesting(
            Date().addingTimeInterval(-899) // 15 min - 1 sec
        )
        XCTAssertTrue(manager.isSessionValid)
    }

    /// invalidateSession clears all state
    func test_invalidateSession_clearsEverything() {
        manager.isAuthenticated = true
        manager.setLastAuthTimeForTesting(Date())
        XCTAssertTrue(manager.isSessionValid)

        manager.invalidateSession()
        XCTAssertFalse(manager.isAuthenticated)
        XCTAssertFalse(manager.isSessionValid)
    }

    /// authenticateForSensitiveData skips re-auth if session valid
    func test_sensitiveData_skipsReauthIfSessionValid() async {
        FeatureFlags.biometricAuthEnabled = false
        await manager.authenticate()
        let result = await manager.authenticateForSensitiveData(
            reason: "Access health records"
        )
        XCTAssertTrue(result,
            "Must skip re-auth when session is still valid")
        FeatureFlags.biometricAuthEnabled = true
    }
}
```

The `setLastAuthTimeForTesting()` method is a test hook that bypasses the normal auth flow. It's marked as `public` for testing but should not be part of the public API contract. In production, `lastAuthTime` is only set after a successful LAContext evaluation.

The idle monitor listens for three system notifications:
1. `NSWorkspace.screensDidSleepNotification` -- screen sleep
2. `NSWorkspace.sessionDidResignActiveNotification` -- fast user switching
3. `com.apple.screenIsLocked` -- screen lock

All three call `invalidateSession()`, which sets `isAuthenticated = false` and `lastAuthTime = nil`.

```swift
// The idle monitor setup (from BiometricAuthManager)
private func setupIdleMonitor() {
    #if canImport(AppKit) && !targetEnvironment(simulator)
    NSWorkspace.shared.notificationCenter.addObserver(
        forName: NSWorkspace.screensDidSleepNotification,
        object: nil, queue: .main
    ) { [weak self] _ in
        Task { @MainActor in self?.invalidateSession() }
    }

    NSWorkspace.shared.notificationCenter.addObserver(
        forName: NSWorkspace.sessionDidResignActiveNotification,
        object: nil, queue: .main
    ) { [weak self] _ in
        Task { @MainActor in self?.invalidateSession() }
    }

    DistributedNotificationCenter.default().addObserver(
        forName: NSNotification.Name("com.apple.screenIsLocked"),
        object: nil, queue: .main
    ) { [weak self] _ in
        Task { @MainActor in self?.invalidateSession() }
    }
    #endif
}
```

You cannot directly test notification delivery in xctest (no AppKit event loop), but you can test the `invalidateSession()` method that all three handlers call:

```swift
func test_invalidateSession_afterAuthentication_clearsSessionCompletely() async {
    FeatureFlags.biometricAuthEnabled = false
    await manager.authenticate()
    XCTAssertTrue(manager.isSessionValid)

    // Simulate what screensDidSleep handler does
    manager.invalidateSession()

    XCTAssertFalse(manager.isAuthenticated)
    XCTAssertFalse(manager.isSessionValid)
    // Re-auth required for sensitive data
    FeatureFlags.biometricAuthEnabled = true
    let needsReauth = await manager.authenticateForSensitiveData(
        reason: "After screen lock")
    // Will fail because biometric auth can't succeed in xctest
    XCTAssertFalse(needsReauth,
        "After invalidation, sensitive data access must require re-auth")
}
```

The `[weak self]` in the notification handlers prevents a retain cycle. The `Task { @MainActor in }` wrapper ensures `invalidateSession()` runs on the main actor, matching the class's `@MainActor` isolation.

