Three security issues to address:

**1. No salt in SHA256 hashing.** Without a salt, identical passcodes produce identical hashes across all devices. An attacker with keychain access can use rainbow tables.

```swift
// VULNERABLE
private func hashPasscode(_ passcode: String) -> String {
    let data = Data(passcode.utf8)
    let hash = SHA256.hash(data: data)
    return hash.compactMap { String(format: "%02x", $0) }.joined()
}

// FIXED: Per-device salt
private func hashPasscode(_ passcode: String) -> String {
    let salt = getOrCreateDeviceSalt()
    let salted = Data((salt + passcode).utf8)
    let hash = SHA256.hash(data: salted)
    return hash.compactMap { String(format: "%02x", $0) }.joined()
}
```

**2. No rate limiting on verifyPasscode.** A 4-digit PIN has only 10,000 combinations. Without rate limiting, brute force takes seconds.

```swift
// FIXED: Lockout after 5 failed attempts
private var failedAttempts = 0
private var lockoutUntil: Date?

func verifyPasscode(_ passcode: String) throws -> Bool {
    if let lockout = lockoutUntil, Date() < lockout {
        throw PasscodeError.tooManyAttempts
    }
    guard let storedHash = try getStoredPasscodeHash() else {
        throw PasscodeError.noPasscodeSet
    }
    let isValid = hashPasscode(passcode) == storedHash
    if isValid {
        failedAttempts = 0
        isLocked = false
    } else {
        failedAttempts += 1
        if failedAttempts >= 5 {
            lockoutUntil = Date().addingTimeInterval(300)
        }
    }
    return isValid
}
```

**3. Minimum length enforcement is correct (4 chars) but could be higher.**

